import { Component, OnInit, signal, computed } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { ProjectService } from '../../../core/services/project.service';
import { Project } from '../../../shared/models/project.model';

@Component({
  selector: 'app-project-list',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './project-list.component.html',
  styleUrl: './project-list.component.scss'
})
export class ProjectListComponent implements OnInit {
  // --- Data ---
  allProjects = signal<Project[]>([]);
  availableTags = signal<string[]>([]);
  availableTech = signal<string[]>([]);

  // --- Filter state ---
  selectedTag = signal<string>('All');
  selectedTech = signal<Set<string>>(new Set());

  // --- Derived: filtered results ---
  filteredProjects = computed(() => {
    const tag = this.selectedTag();
    const tech = this.selectedTech();

    return this.allProjects().filter(project => {
      const tagMatch = tag === 'All' || project.tags.includes(tag);
      const techMatch = tech.size === 0 || [...tech].every(t => project.tech.includes(t));
      return tagMatch && techMatch;
    });
  });

  // --- Derived: active filter count for UI badge ---
  activeFilterCount = computed(() => {
    let count = 0;
    if (this.selectedTag() !== 'All') count++;
    count += this.selectedTech().size;
    return count;
  });

  constructor(private projectService: ProjectService) {}

  ngOnInit() {
    this.projectService.getProjects().subscribe(p => this.allProjects.set(p));
    this.projectService.getAllTags().subscribe(t => this.availableTags.set(t));
    this.projectService.getAllTechStacks().subscribe(t => this.availableTech.set(t));
  }

  selectTag(tag: string) {
    this.selectedTag.set(tag);
  }

  toggleTech(tech: string) {
    // Signals require a new Set reference to trigger change detection
    const current = new Set(this.selectedTech());
    current.has(tech) ? current.delete(tech) : current.add(tech);
    this.selectedTech.set(current);
  }

  isTechSelected(tech: string): boolean {
    return this.selectedTech().has(tech);
  }

  clearAllFilters() {
    this.selectedTag.set('All');
    this.selectedTech.set(new Set());
  }
}
